/*====スタート====*/
@import url("https://fontsapi-storage.zeoseven.com/482/main/result.css");

body {
    font-family: "CooperZhengKai";
    font-weight: normal;
}
/* Apply custom font to input fields */
input[type="text"],
input[type="number"],
textarea,
.text_pole,
.search_field {
    font-family: "CooperZhengKai", sans-serif !important; /* Replace "undefined" with your actual font name */
}

/* Apply custom font to code blocks */
pre,
code,
.hljs,
pre code {
    font-family: "CooperZhengKai", monospace !important;
}
#send_textarea:placeholder-shown {
     font-family: "CooperZhengKai";
     font-weight: normal;
     font-size: 15.5px;
}
/* 底栏QR按键隐藏 */#send_form:hover #qr--bar {    height: 40px;    transition: all 0.5s ease;}#qr--bar {    height: 0.01px;}
/* qr隐藏插件 */
  #quick-reply-rocket-button {
    font-size: 20px !important;
  }

.inline-drawer-header.gap5px.padding0 {
  position: relative;
  display: flex;
  align-items: center;
  gap: 5px;
  padding: 10px 14px;
  background: radial-gradient(circle at 30% 30%, rgba(80, 60, 110, 0.3), rgba(40, 30, 60, 0.2));
  border: 1px solid rgba(180, 160, 230, 0.25);
  border-radius: 12px;
  color: #e2d4ff;
  font-family: 'JetBrains Mono', 'Georgia', serif;
  font-size: 13px;
  line-height: 1.5;
  box-shadow:
    inset 0 0 5px rgba(160, 140, 220, 0.08),
    0 0 6px rgba(120, 100, 200, 0.12);
  backdrop-filter: blur(3px);
  overflow: hidden;
}


.inline-drawer-header.gap5px.padding0::after {
  content: '';
  position: absolute;
  top: 6px;
  right: 8px;
  width: 20px;
  height: 20px;
  background: url('http://img.nagadnd.club/i/2025/05/17/vh1sf6.png') no-repeat center center;
  background-size: contain;
  opacity: 0.9;
  animation: floatButterfly 3s ease-in-out infinite;
  pointer-events: none;
  filter: drop-shadow(0 0 4px rgba(200, 150, 255, 0.4));
}

/* 漂浮动画 */
@keyframes floatButterfly {
  0% { transform: translateY(0) rotate(0deg); }
  50% { transform: translateY(-3px) rotate(2deg); }
  100% { transform: translateY(0) rotate(0deg); }
}
.flex-container.wide100p.alignitemscenter {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: 100%;
  padding: 14px 20px;
  background: linear-gradient(
    130deg,
    rgba(50, 40, 70, 0.35),
    rgba(30, 20, 50, 0.25)
  );
  border: 1px solid rgba(190, 160, 240, 0.15);
  border-radius: 16px;
  box-shadow:
    inset 0 0 4px rgba(120, 100, 180, 0.1),
    0 0 6px rgba(90, 80, 140, 0.08);
  backdrop-filter: blur(2px);
  color: #e6dcff;
  font-family: 'Caveat', 'JetBrains Mono', 'Georgia', serif;
  font-size: 14px;
  line-height: 1.7;
  overflow: hidden;
}


.flex-container.wide100p.alignitemscenter::before {
  content: '';
  position: absolute;
  top: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 100%;
  height: 100%;
  background: url('http://img.nagadnd.club/i/2025/05/17/vihmhj.jpg') no-repeat center center;
  background-size: contain;
  opacity: 0.08;
  pointer-events: none;
  z-index: 0;
}


.flex-container.wide100p.alignitemscenter::after {
  content: '';
  position: absolute;
  bottom: 6px;
  right: 10px;
  width: 22px;
  height: 22px;
  background: url('http://img.nagadnd.club/i/2025/05/15/ubjv68.png') no-repeat center center;
  background-size: contain;
  opacity: 0.9;
  animation: floatButterflyCard 4s ease-in-out infinite;
  pointer-events: none;
  z-index: 1;
  filter: drop-shadow(0 0 4px rgba(190, 130, 255, 0.4));
}

@keyframes floatButterflyCard {
  0% { transform: translateY(0) rotate(0deg); }
  50% { transform: translateY(-4px) rotate(1deg); }
  100% { transform: translateY(0) rotate(0deg); }
}




#user_avatar_block .avatar-container {
  position: relative;
  display: flex;
  align-items: center;
  gap: 12px;
  margin: 6px 0;
  padding: 10px 14px;
  border-radius: 6px; /* 减少圆角，别那么可爱 */
  background: rgba(50, 45, 65, 0.3);
  border: 1px solid rgba(120, 110, 160, 0.3);
  box-shadow: 0 2px 6px rgba(80, 70, 120, 0.08);
  transition: background 0.3s ease, box-shadow 0.3s ease;
  cursor: pointer;
}

/* hover 提亮但内敛 */
#user_avatar_block .avatar-container:hover {
  background: rgba(70, 65, 100, 0.4);
  box-shadow: 0 3px 7px rgba(100, 90, 160, 0.12);
}

/* 选中状态 - 微光灰紫 */
#user_avatar_block .avatar-container.selected {
  border: 1.5px solid rgba(180, 170, 240, 0.5);
  background: rgba(70, 60, 120, 0.4);
}

/* 默认角色外轮廓隐藏 */
#user_avatar_block .avatar-container.default_persona .avatar {
  outline: none;
}

/* 被选中头像 - 柔和发光 */
#user_avatar_block .avatar-container.selected .avatar {
  box-shadow: 0 0 8px rgba(150, 140, 220, 0.3);
  border-radius: 50%;
  transition: box-shadow 0.3s ease;
}

/* 漂浮符号动画 */
@keyframes bubbleFloat {
  0% {
    transform: translateY(0) scale(0.85);
    opacity: 0.3;
  }
  50% {
    transform: translateY(-8px) scale(1);
    opacity: 0.8;
  }
  100% {
    transform: translateY(-16px) scale(1.2);
    opacity: 0;
  }
}

/* 符号更克制：小钻感的 ✧，配合暗调色 */
#user_avatar_block .avatar-container.selected::after {
  content: "✧";
  position: absolute;
  top: 5px;
  right: 10px;
  font-size: 16px;
  color: rgba(190, 180, 240, 0.7);
  animation: bubbleFloat 1.2s ease-out;
  pointer-events: none;
}

/* 入场动画 */
@keyframes fadeSlideIn {
  from {
    opacity: 0;
    transform: translateY(10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}
#user_avatar_block .avatar-container {
  animation: fadeSlideIn 0.4s ease forwards;
}

/* 头像 hover 微缩放 */
#user_avatar_block .avatar-container .avatar {
  transition: transform 0.3s ease;
}
#user_avatar_block .avatar-container:hover .avatar {
  transform: scale(1.05);
}

/* === 蓝紫夜感输入模块 === */

/* 默认状态*/
input[type="text"],
input[type="number"],
input[type="switch"],
input:not([type]),
textarea:not([type="search"]) {
  background-color: rgba(50, 40, 80, 0.25) !important;
  color: #dcd3ff !important;
  border: 1px solid rgba(180, 160, 230, 0.3) !important;
  caret-color: #c8aaff !important;
  border-radius: 6px;
  padding: 8px 12px;
  font-size: 14px;
  line-height: 1.4;
  transition: all 0.2s ease;
  box-shadow: none;
}

/* 聚焦状态：紫蓝背景+微光边框 */
input:focus,
textarea:focus {
  background-color: rgba(70, 60, 120, 0.35) !important;
  color: #f0e6ff !important;
  border-color: rgba(200, 180, 255, 0.4) !important;
  box-shadow: 0 0 4px rgba(170, 140, 240, 0.15);
  outline: none;
}

/* placeholder 提示语：微紫柔色 */
input::placeholder,
textarea::placeholder {
  color: rgba(200, 180, 240, 0.3) !important;
}
/*====スタート====*/

/*尾部消息处理*/
.last_mes .mes_text {
  padding-right: 0;
}

.last_mes .mesAvatarWrapper {
  padding-bottom: 0;
}

/* 插播一下 */
body {
    background-color: #141418; /* 更深的夜黑，带点冷感 */
    color: #9c9cab; /* 主体文字：雾紫灰，低对比、耐看 */
    font-size: 13px;
    line-height: 1.6;
}

/* 加粗文字 - 提亮一点点但不跳出来，像夜里突然认真了一句 */
strong, b {
    color: #dad6f0;
    background-color: rgba(100, 100, 140, 0.12);
    padding: 1px 4px;
    border-radius: 4px;
    font-weight: 600;
}

/* 链接文字 - 淡淡的幽蓝 */
a {
    color: #8e91c2;
    text-decoration: underline dotted;
}
a:hover {
    color: #b2b4e5;
}

/* 斜体 - 微紫灰，像在梦里叨叨一句话 */
em, i {
    color: #aaa7be;
}

/* 隐藏原始复选框 */
input[type="checkbox"] {
    appearance: none;
    -webkit-appearance: none;
    background-color: transparent;
    border: 1px solid rgba(120, 100, 180, 0.5);
    width: 18px;
    height: 18px;
    border-radius: 4px;
    cursor: pointer;
    position: relative;
    vertical-align: middle;
    margin-right: 6px;
}


input[type="checkbox"]:checked::after {
    content: "✣";
    color: white;
    font-size: 13px;
    position: absolute;
    top: 0px;
    left: 2px;
}



/* ====バブル====*/
#chat {
    backdrop-filter: none !important;
    bottom: 0;
}
/* 背景 */
body {
    background-size: cover;
    filter: brightness(0.95) contrast(1.05); /* 轻微调整让背景更柔和 */
}


.mes_text {
    position: relative;
    width: 120vw;
    padding: 15px 20px !important;
    border: none !important;
    border-radius: 14px;
    background: radial-gradient(
        circle at center,
        rgba(70, 70, 90, 0.25),
        rgba(60, 60, 80, 0.1)
    ) !important;
    box-shadow:
        inset 0 0 3px rgba(100, 110, 140, 0.1),
        0 0 4px rgba(80, 90, 120, 0.05);
    box-sizing: border-box;
    backdrop-filter: blur(1px);
}


/* 移动端适配 */
@media (max-width: 768px) {
    .mes {
        padding: 0;
    }
    .mes_block {
        width: 150%;
    }
}

/* 消息容器 */
.mes {
    position: relative;
    margin: 0.75em 0;
    padding: 16px 20px;
    padding-bottom: 28px; /* 增加底部padding，为图片留出空间 */
    background: linear-gradient(145deg, rgba(60, 65, 80, 0.5), rgba(50, 55, 70, 0.6)) !important;
    color: #e9e7f2;
    width: 100%;
    flex-direction: column;
    align-items: center;
    border-radius: 18px !important;
    box-shadow: 
        0 0 4px rgba(170, 190, 255, 0.08),
        inset 0 0 3px rgba(100, 110, 140, 0.15);
    backdrop-filter: blur(0.2px);
    transition: background 0.3s ease;
}


.mes::after {
    content: '';
    position: absolute;
    bottom: 8px;  /* 距离底部的距离 */
    right: 12px;  /* 距离右侧的距离 */
    width: 32px;  /* 图片宽度 */
    height: 32px; /* 图片高度 */
    background-image: url('http://img.nagadnd.club/i/2025/05/16/qoydoa.png');
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    opacity: 0.85; /* 稍微调整透明度，让它更融入背景 */
    pointer-events: none; /* 确保图片不会影响文字选择 */
}

/* 悬停效果（可选） */
.mes:hover::after {
    opacity: 1;
    transform: scale(1.05);
    transition: all 0.3s ease;
}

/* 气泡内容区域 */
.mes_block {
    margin: 0 !important;
    width: 110%;
    padding-left: 0;
}

/*ui背景图*/
.drawer-content {
    background-image: url('http://img.nagadnd.club/i/2025/05/15/1yjq6j.jpg');
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
}
/* 聊天气泡整体背景 */
#chat .mes {
    background-color: rgba(235, 245, 245, 0.1) !important;
    border-radius: 25px;
    padding: 10px 25px;
    box-shadow: 2px 2px 6px rgba(180, 220, 220, 0.1) !important;
}

/* 大头像适配 */
body.big-avatars #chat .mes .mes_block {
    border-radius: 10px;
}

/* 消息间距 */
.mes {
    padding: 10px;
    margin-bottom: 5px;
}

/* 引用文本 */
/* 引用文字样式：夜紫+手写体 */


body.bubblechat .mes q {
  display: inline-block;
  color: #cab9ff; /* 夜紫冷感 */
  font-style: italic;
  font-size: 1.1em;
  padding: 0.25em 0.5em;
  border-bottom: 1px dashed rgba(180, 140, 255, 0.4);
  background: transparent;
  border-radius: 2px;
  position: relative;
  margin-right: 1.6em;
  transition: all 0.2s ease;
}

/* 镂空、细致 */
body.bubblechat .mes q::after {
  content: "𖤐"; /* 镂空字符 */
  font-family: serif;
  color: #bfa2ff;
  position: absolute;
  right: -1.2em;
  bottom: 0;
  font-size: 1em;
  opacity: 0.8;
  transition: transform 0.2s ease, opacity 0.2s ease;
}

/* 悬停：轻飘感 */
body.bubblechat .mes q:hover::after {
  transform: translateY(-2px) scale(1.05);
  opacity: 1;
}

