}

/*====メッセージ==== */
#chat .mes[is_user="true"]  {
background-color: rgba(255, 255, 255, 0.5); 
}

/* 代码块容器 */
body.bubblechat .mes pre::before,
.markdown-body pre::before {
    content: "";
    position: absolute;
    top: 50%;
    left: 50%;
    width: 150px;  /* 调整大小 */
    height: 150px;
    background-image: url('http://img.nagadnd.club/i/2025/05/15/ubjv68.png');
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    opacity: 0.05;
    pointer-events: none;
    transform: translate(-50%, -50%);
    z-index: 0;
}
body.bubblechat .mes pre,
.markdown-body pre {
    position: relative; /* 伪元素定位基准 */
    background: rgba(40, 45, 60, 0.6) !important;
    border-radius: 12px !important;
    padding: 14px 20px !important;
    border: 1px solid rgba(120, 130, 160, 0.4);
    box-shadow: 0 0 4px rgba(100, 120, 180, 0.1);
    overflow: auto;
    color: #dcdcf0;

}

/* 小符文装饰 */
body.bubblechat .mes pre::after,
.markdown-body pre::after {
    content: '⌘';  /* 魔法符号感，低调神秘 */
    position: absolute;
    bottom: 8px;
    right: 12px;
    font-size: 14px;
    color: rgba(160, 170, 210, 0.4);
    pointer-events: none;
}

/* 代码颜色 */
.mes_text pre code {
    color: #c8ccee;  /* 柔雾蓝字色 */
}

body.bubblechat .mes pre code,
.markdown-body pre code {
    background: transparent !important; 

    padding: 0 !important;          
    border: none !important;          
    font-size: inherit !important;    
}

/*行内代码 */
body.bubblechat .mes code:not(pre code),
.markdown-body code:not(pre code) {
    background: rgba(80, 85, 110, 0.25) !important;
    color: #c5c8de !important;
    border-radius: 4px !important;
    padding: 2px 4px !important;
    border: 1px solid rgba(140, 145, 180, 0.2) !important;
    font-size: 0.9em !important;
    font-family: 'JetBrains Mono', monospace;
}

/*====せっち====*/

/* 移动端滚动条隐藏 */
@media screen and (max-width: 1000px) {
    *::-webkit-scrollbar {
        display: none;
    }

    * {
        scrollbar-width: none;
        -ms-overflow-style: none;
    }
}


/* === 夜间魔女风 === */

/* 全局背景基调可加上 */
body {
    background-color: #181220 !important;
    color: #e2dcff !important;
}

/* 开关按钮 -  */
.world_entry .killSwitch.fa-toggle-on {
    background: linear-gradient(145deg, #5c4b8a, #7c5cd9) !important;
    -webkit-background-clip: text !important;
    -webkit-text-fill-color: transparent !important;
    text-shadow:
        0 0 4px rgba(100, 80, 180, 0.3),
        0 0 8px rgba(120, 100, 200, 0.2);
}

/* 滑动输入块 -  */
.neo-range-input {
    background: rgba(70, 50, 110, 0.2) !important;
    border-radius: 10px;
    box-shadow: inset 0 1px 3px rgba(80, 60, 120, 0.2);
}

/* 滑动条 -  */
input[type="range"] {
    height: 8px !important;
    background: linear-gradient(
        to right,
        #3b2b4d 0%,
        #5a3f88 40%,
        #735bca 100%
    ) !important;
    border-radius: 4px !important;
    box-shadow: inset 0 1px 2px rgba(50, 40, 90, 0.2) !important;
}

/* 下拉菜单 - */
select, select option {
    background-color: rgba(40, 30, 70, 0.8) !important;
    color: #d0c7f7 !important;
    border: 1px solid rgba(110, 90, 160, 0.4);
}

/* 菜单按钮 -  */
.menu_button {
    color: #cbbfff;
    background-color: rgba(50, 40, 90, 0.4);
    border: 1px solid rgba(100, 80, 150, 0.4);
    border-radius: 6px;
    transition: all 0.2s ease;
}
.menu_button:hover {
    background-color: rgba(70, 60, 110, 0.5);
    box-shadow: 0 0 6px rgba(140, 120, 200, 0.2);
}
.menu_button:active {
    background-color: rgba(60, 50, 100, 0.5);
}

/* 图标 hover 紫光浮动 */
.custom-drawer-icon,
.inline-drawer-icon {
    color: #a490ff !important;
    transition: transform 0.3s ease;
}
.custom-drawer-icon:hover {
    transform: rotate(90deg);
    color: #c0aaff !important;
}

/* 顶栏背景 - */
#top-settings-holder {
    background: linear-gradient(
        145deg,
        rgba(30, 20, 50, 0.5),
        rgba(45, 30, 60, 0.4)
    ) !important;
    backdrop-filter: blur(5px);
}

/* 标题样式 -  */
#extensions_settings .inline-drawer-toggle.inline-drawer-header, 
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header, 
#user-settings-block h4, 
.standoutHeader {
    background-color: transparent !important;
    color: #dacfff !important;
    text-shadow: 
        0 0 6px rgba(160, 140, 220, 0.3),
        0 0 12px rgba(130, 110, 200, 0.2);
    border-bottom: 1px solid rgba(120, 90, 170, 0.4) !important;
    border-radius: 6px 6px 0 0;
}

/* 标题 hover 光效增强 */
.standoutHeader:hover {
    text-shadow: 
        0 0 10px rgba(190, 170, 255, 0.5),
        0 0 18px rgba(150, 130, 230, 0.3);
    border-bottom-color: rgba(180, 150, 240, 0.5) !important;
}

/* 内部按钮 - */
.send-tools button {
    background: rgba(60, 50, 90, 0.5) !important;
    border: 1px solid rgba(110, 90, 160, 0.3) !important;
    border-radius: 8px !important;
    color: #e4dcff !important;
    transition: all 0.3s ease !important;
}
.send-tools button:hover {
    background: rgba(80, 70, 120, 0.5) !important;
    box-shadow: 0 0 6px rgba(160, 130, 230, 0.2);
}

/* 选中内容星光闪 */
::selection {
    background: rgba(130, 100, 200, 0.3);
    color: #fff;
}


/*背景图片*/
.bg_list {
    display: flex;
    flex-wrap: wrap;
    max-width: 100vw;
    justify-content: center;
    margin: 0 auto;
    padding: 0;
    box-sizing: border-box;
    overflow: hidden;
    gap: 5px;
}

.bg_list > * {
    width: calc(20% - 5px); /* Makes items take up 1/5 of container width minus the gap */
    box-sizing: border-box;
}
/* =======分割======== */

#HotSwapWrapper {
  overflow: hidden;
}

#HotSwapWrapper > div {
  overflow: auto hidden;
  flex-wrap: nowrap;
  height: calc(var(--avatar-base-height) + var(--scroll-width) + 10px);
  max-height: calc(var(--avatar-base-height) * 2);
}
body.big-avatars #HotSwapWrapper > div {
  height: calc(
    var(--avatar-base-height) * var(--big-avatar-height-factor) +
      var(--scroll-width) + 10px
  );
  max-height: calc(
    var(--avatar-base-height) * var(--big-avatar-height-factor) * 2
  );
}

#HotSwapWrapper > div::-webkit-scrollbar-thumb {
  background-color: var(--ui-color-sec);
}

#user_avatar_block {
  max-height: 300px;
  overflow-y: auto;
  overflow-x: hidden;
  padding-right: 4px;
  scrollbar-width: thin;
}

/* === 优化版 === */

/* === 工具栏 -  === */
.send-tools {
    background: linear-gradient(
        to bottom,
        rgba(40, 30, 60, 0.7) 0%,
        rgba(30, 25, 50, 0.6) 100%
    ) !important;
    backdrop-filter: blur(6px);
    border-radius: 8px 8px 0 0;
}

/* 工具栏按钮 -  */
.send-tools button {
    background: rgba(90, 70, 140, 0.5) !important;
    color: #e3d9ff !important;
    border: 1px solid rgba(120, 100, 180, 0.3);
    border-radius: 6px;
    transition: all 0.2s ease;
}
.send-tools button:hover {
    background: rgba(110, 90, 160, 0.6) !important;
    box-shadow: 0 0 6px rgba(140, 110, 200, 0.3);
